VALUES
  ('pukao-7ec62a85-moex-00202', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-111-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '關於行政罰之敘述，下列何者錯誤？', '["一行為同時觸犯刑事法及違反行政法上義務者，依刑事法處罰", "一行為同時觸犯刑事法及違反行政法上義務，刑事部分獲無罪確定者，不得再以違反行政法上義務之規 定裁處之", "一行為違反社會秩序維護法及其他行政法上義務者而應受處罰時，如已裁處拘留者，不得再處以罰鍰", "一行為違反數個行政法上義務而應處罰鍰者，依法定罰鍰額最高之規定裁處"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "d0ebedea4ae8", "answer_pdf_sha1": "cec5c3149dc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "418", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00203', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-111-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '關於行政罰裁處權時效之敘述，下列何者錯誤？', '["行政罰之裁處權，因2年期間之經過而消滅", "裁處權時效，因天災、事變或依法律規定不能開始或進行裁處時，停止其進行", "行政罰之裁處權期間，原則上自違反行政法上義務之行為終了時起算", "行政罰之裁處因訴願等經撤銷而須另為裁處者，裁處權期間自原裁處被撤銷確定之日起算"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "d0ebedea4ae8", "answer_pdf_sha1": "cec5c3149dc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "418", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00204', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-111-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '下列何者非行政執行機關當然應依職權停止行政執行程序之法定事由？', '["行政執行義務人之義務已全部履行", "行政執行所憑之執行名義行政處分，經原處分機關之上級機關予以撤銷", "行政執行義務人應履行之義務經證明為不可能", "債務人主張對其所採取之查封手段過於嚴苛，聲明異議"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "d0ebedea4ae8", "answer_pdf_sha1": "cec5c3149dc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "418", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00205', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-111-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '關於直接強制方法之種類，不包括下列何者？', '["收繳、註銷證照", "處以怠金", "限制使用動產、不動產", "拆除住宅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "d0ebedea4ae8", "answer_pdf_sha1": "cec5c3149dc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "418", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00206', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-111-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '依實務見解，關於即時強制之敘述，下列何者正確？', '["甲員警見路人爛醉如泥，跌倒於車道上，得先將當事人載往警局，保護其生命", "乙員警於治安熱點，見陌生女性經過，即上前盤查其身分，遭拒絕後，將其壓制在地", "丙員警為避免當事人意圖自殺，將其管束於警局內，直至48小時當事人回復平靜後，始恢復其自由", "丁員警嚇阻鬥毆之行為人後，得任意使用手銬，銬住行為人之手"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "d0ebedea4ae8", "answer_pdf_sha1": "cec5c3149dc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "418", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00207', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-111-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '下列何種政府資訊，原則上非屬法律規定應主動公開者？', '["承辦公務員之擬稿", "國家通訊傳播委員會會議紀錄", "行政院年度中央政府總預算書", "與外國簽訂之犯罪引渡條約"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "d0ebedea4ae8", "answer_pdf_sha1": "cec5c3149dc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "418", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00208', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-111-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '關於行政程序法適用之敘述，下列何者錯誤？', '["立法院拒絕民眾申請參觀立法院時，不適用行政程序法", "內政部移民署就本國人之入、出境許可，不適用行政程序法", "外交部就援助友邦之行為，不適用行政程序法", "檢察官指派司法警察調查犯罪嫌疑人之犯罪事證，不適用行政程序法"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "d0ebedea4ae8", "answer_pdf_sha1": "cec5c3149dc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "418", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00209', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-111-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '行政程序法之寄存送達，應自何時發生送達效力？', '["寄存送達完畢時", "自寄存之日起，經10日發生效力", "寄存機關保存期滿日之翌日", "自應受送達人實際領取時"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "d0ebedea4ae8", "answer_pdf_sha1": "cec5c3149dc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "418", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00210', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-111-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '關於聽證程序踐行之效力等敘述，下列何者錯誤？', '["法律明文規定應舉行聽證作成決定，而未舉行者，該決定得撤銷", "聽證程序中，當事人認為主持人所為之處置違法時得提起抗告", "當事人對經聽證程序作成之行政處分不服者，得直接提起行政訴訟救濟", "聽證得由行政機關首長擔任主持人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "d0ebedea4ae8", "answer_pdf_sha1": "cec5c3149dc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "418", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00211', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-111-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '依訴願法規定，關於訴願提起之程序，下列敘述何者錯誤？', '["訴願之提起，應自行政處分達到之次日起30日內為之", "訴願人誤向原行政處分以外之機關作不服之表示者，視為自始向訴願管轄機關提起訴願", "訴願人應繕具訴願書直接向訴願管轄機關提起訴願", "訴願人在法定期間內向訴願管轄機關作不服之表示者，視為已在法定期間內提起訴願，但應於 30日內 補送訴願書"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "d0ebedea4ae8", "answer_pdf_sha1": "cec5c3149dc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "418", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL)
